I wrote a code to encrypt a word using Vigenère, It doesn't work as supposed while it seems all correct.
I have examples of 2 inputs which give undesired outputs, not that any input worked so far.
First, the code: 
#include <stdio.h>
#include <stdlib.h>
#include <cs50.h>
#include <string.h>
//return 1= wrong amount of args
//return 2= non alphabetical string arg
//return 3= non alphabetical string plaintext

int main(int argc, string argv[])
{
    //checking if right amount of args
    if(argc!=2)
    {
        printf("Please insert 1 argument.\n");
        return(1);
    }
    //declaring keyword as k and checking if k is alphabetical

    string k= argv[1];
    for(int z=0; z<strlen(k); z++)
    {
        char keywordth=k[z];
        if(!(('a'<=keywordth && keywordth<='z') || ('A'<=keywordth && keywordth<='Z' )))
        {
            printf("Please make sure you enter a alphabetical string into the argument.\n");
            return(2);
        }
    }
    //asking for plaintext
    printf("Please insert word to be ciphered.\n");
    string plaintext= get_string();
    //checking if plaintext is alphabetical
    for(int p=0; p<strlen(plaintext); p++)
    {
        char plaintextth=plaintext[p];
        if(!(('a'<=plaintextth && plaintextth<='z') || ('A'<=plaintextth && plaintextth<='Z' )))
        {
            printf("Please make sure you enter a alphabetical string as plaintext.\n");
            return(3);
        }
    }
    //encrypting chars
    for(int o=0; o<strlen(plaintext); o++)
    {
        char plaintextth= plaintext[o];
        int keywordloc= strlen(plaintext)%strlen(k);
        char keywordth= k[keywordloc-1];
        //if keywordth is undercase
        if('a'<=keywordth && keywordth<='z')
        {
            int keywordthnum= keywordth-'a';
            char ciphered= plaintextth+keywordthnum;
            //if keywordth is undercase and after cipher it is bigger than 'Z' and less than 'a'
            if('Z'<ciphered && ciphered<'a')
            {
                int charoverflow= ciphered-'Z';
                char result= 'A'+ charoverflow-1;
                printf("%c", result);
            }
            //if keywordth is undercase and after cipher it is bigger than 'z'
            else if('z'<ciphered)
            {
                int charoverflow= ciphered-'z';
                char result= 'a'+ charoverflow-1;
                printf("%c", result);
            }
            //if keywordth is undercase and does not overflow
            else
            {
                char result= ciphered;
                printf("%c", result);
            }
        }
        //if keywordth is uppercase
        else if('A'<=keywordth && keywordth<='Z')
        {
            int keywordthnum= keywordth-'A';
            char ciphered= plaintextth+keywordthnum;
            //if keywordth is uppercase and after cipher it is bigger than 'Z' and less than 'a'
            if('Z'<ciphered && ciphered<'a')
            {
                int charoverflow= ciphered-'Z';
                char result= 'A'+ charoverflow-1;
                printf("%c", result);
            }
            //if keywordth is uppercase and after cipher it is bigger than 'z'
            else if('z'<ciphered)
            {
                int charoverflow= ciphered-'z';
                char result= 'a'+ charoverflow-1;
                printf("%c", result);
            }
            //if keyword is uppercase and does not oveflow
            else
            {
                char result= ciphered;
                printf("%c", result);
            }
        }
    }
    printf("\n");
    return(0);
}



Now the bugs:
