print(graphql.parse("""
            query {
                user(id: 1) { foo {
                        bar(arg:"2") {
                            id
                        }
                    }
                }
            }
        """) == graphql.parse("""
            query {
                user(id: 1) { foo { bar(arg:"2") {
                            id
                        }
                    }
                }
            }
        """))
# prints false
